// AI Card Battle — card registry + decklists (Phase-0, all four factions).
// Balance-review fixes applied (see docs/CARDS.md). Handlers mutate ONLY via
// ctx.api (which resolves deaths / On Sunset / win checks).
// Some twists are simplified for the prototype and flagged with [sim].

function bestFriendly(api) { const b = api.myBoard(); return b.length ? b.reduce((a, m) => (m.attack >= a.attack ? m : a)) : null; }

