export const HERO_POWERS = {
  ClosedAI: { name: "Hype Ping", cost: 2, requiresTarget: true,
    targets: (S, seat) => { const o = seat === "A" ? "B" : "A"; return [...S.players[o].board.filter((m) => !m.stealth).map((m) => m.iid), "HERO_" + o]; },
    use: (S, c) => { const tid = c.targetId; c.api.dealDamage(tid, 1); const killed = tid.startsWith("m") && !c.api.findModel(tid); const face = tid === "HERO_" + c.api.opp; if (killed || face) { const m = bestFriendly(c.api); if (m) c.api.giveHype(m, 1); } } },
  Anthrabbit: { name: "Realign", cost: 2, requiresTarget: false,
    use: (S, c) => { if (c.me.valuation >= c.me.maxValuation) c.api.gainArmor(2); else c.api.heal(2); } },
  Googlitch: { name: "Index & Scry", cost: 2, requiresTarget: false, use: (S, c) => c.api.draw(1) },
  ShallowSeek: { name: "Spin Up", cost: 2, requiresTarget: false, use: (S, c) => c.api.addTempCompute(1) },
};

function dup(ids) { return ids.flatMap((id) => [id, id]); }

